                  BigDecimal bounty, Long shipId, LocalDate joinedAt) {
        this.id = id;
        this.name = name;
        this.nickname = nickname;
        this.rank = rank;
        this.bounty = bounty;
        this.shipId = shipId;
        this.joinedAt = joinedAt;
    }

