            // 🔍 OBSERWUJ: Commit - tu wykonuje się DELETE
            System.out.println("\n   🔍 OBSERWUJ: Wywołuję commit()...");
            System.out.println("   🔍 OBSERWUJ: Hibernate generuje: DELETE FROM pirates WHERE id=?");
