    // ========================================================================
    // ROZWIĄZANIE 1: Podstawowe JPQL z WHERE
    // ========================================================================
    private static void exercise1Solution() {
        String jpql = """
            SELECT p FROM Pirate p
            WHERE p.bounty > :minBounty
            ORDER BY p.bounty DESC
            """;

        List<Pirate> pirates = em.createQuery(jpql, Pirate.class)
                .setParameter("minBounty", new BigDecimal("50000"))
                .getResultList();

        System.out.println("📋 Piraci z bounty > 50,000:");
        pirates.forEach(p -> System.out.printf("  - %s: $%s%n", p.getName(), p.getBounty()));

        System.out.println("\n💡 Wyjaśnienie:");
        System.out.println("   - WHERE p.bounty > :minBounty - filtrowanie po nagrodzie");
        System.out.println("   - ORDER BY p.bounty DESC - sortowanie malejące");
        System.out.println("   - :minBounty - parametr nazwany (bezpieczny przed SQL injection)");
    }

    // ========================================================================
    // ROZWIĄZANIE 2: JPQL z ORDER BY i paginacją
    // ========================================================================
    private static void exercise2Solution() {
        String jpql = """
            SELECT p FROM Pirate p
            ORDER BY p.bounty DESC
            """;

        TypedQuery<Pirate> query = em.createQuery(jpql, Pirate.class);
        query.setFirstResult(0);  // offset: od którego rekordu (0 = pierwszy)
        query.setMaxResults(3);   // limit: ile rekordów pobrać

        List<Pirate> top3 = query.getResultList();

        System.out.println("📋 TOP 3 najdrożsi piraci:");
        int rank = 1;
        for (Pirate p : top3) {
            System.out.printf("  %d.

%s: $%s%n", rank++, p.getName(), p.getBounty());
        }

        System.out.println("\n💡 Wyjaśnienie:");
        System.out.println("   - setFirstResult(0) - zaczyna od pierwszego rekordu");
        System.out.println("   - setMaxResults(3) - pobiera maksymalnie 3 rekordy");
        System.out.println("   - Dla strony 2: setFirstResult(3) - pomija pierwsze 3");
    }

    // ========================================================================
    // ROZWIĄZANIE 3: JOIN FETCH - rozwiązanie N+1
    // ========================================================================
    private static void exercise3Solution() {
        String jpql = """
            SELECT DISTINCT s FROM Ship s
            LEFT JOIN FETCH s.crew
            LEFT JOIN FETCH s.homePort
            """;

        List<Ship> ships = em.createQuery(jpql, Ship.class).getResultList();

        System.out.println("📋 Statki z załogą (JOIN FETCH):");
        ships.forEach(s -> {
            System.out.printf("  🚢 %s (port: %s)%n",
                    s.getName(),
                    s.getHomePort() != null ? s.getHomePort().getName() : "brak");
            s.getCrew().forEach(p ->
                    System.out.printf("      👤 %s%n", p.getName()));
        });

        System.out.println("\n💡 Wyjaśnienie:");
        System.out.println("   - LEFT JOIN FETCH s.crew - pobiera załogę w tym samym zapytaniu");
        System.out.println("   - LEFT JOIN FETCH s.homePort - pobiera port w tym samym zapytaniu");
        System.out.println("   - DISTINCT - usuwa duplikaty (JOIN może je tworzyć)");
        System.out.println("   - Bez FETCH byłoby N+1: 1 query na statki + N queries na załogi");
    }

    // ========================================================================
    // ROZWIĄZANIE 4: Projekcja SELECT NEW do DTO
    // ========================================================================
    private static void exercise4Solution() {
        String jpql = """
            SELECT NEW pl.przemekzagorski.training.jpa.dto.PirateDTO(
                p.name, p.rank, p.bounty
            )
            FROM Pirate p
            WHERE p.rank = 'Captain'
            ORDER BY p.bounty DESC
            """;

        List<PirateDTO> captains = em.createQuery(jpql, PirateDTO.class)
                .getResultList();

        System.out.println("📋 Kapitanowie jako DTO:");
        captains.forEach(dto ->
                System.out.printf("  ⚓ %s (%s): $%s%n",
                        dto.name(), dto.rank(), dto.bounty()));

        System.out.println("\n💡 Wyjaśnienie:");
        System.out.println("   - SELECT NEW <pełna.nazwa.klasy>(...) - tworzy instancje DTO");
        System.out.println("   - Argumenty muszą pasować do konstruktora DTO");
        System.out.println("   - PirateDTO to record - kompaktowy i immutable");
        System.out.println("   - ZALETA: Pobieramy tylko potrzebne kolumny, nie całą encję");
    }

    // ========================================================================
    // ROZWIĄZANIE 5: Agregacja GROUP BY z HAVING
    // ========================================================================
    private static void exercise5Solution() {
        String jpql = """
            SELECT NEW pl.przemekzagorski.training.jpa.dto.ShipSummaryDTO(
                s.name,
                s.type,
                COUNT(p),
                SUM(p.bounty)
            )
            FROM Ship s
            LEFT JOIN s.crew p
            GROUP BY s.id, s.name, s.type
            HAVING COUNT(p) >= 2
            ORDER BY SUM(p.bounty) DESC
            """;

        List<ShipSummaryDTO> summaries = em.createQuery(jpql, ShipSummaryDTO.class)
                .getResultList();

        System.out.println("📋 Statystyki statków (min.

2 piratów):");
        summaries.forEach(s ->
                System.out.printf("  🚢 %s (%s): %d piratów, $%s%n",
                        s.shipName(), s.shipType(), s.crewCount(), s.totalBounty()));

        System.out.println("\n💡 Wyjaśnienie:");
        System.out.println("   - LEFT JOIN s.crew p - łączy statki z załogą");
        System.out.println("   - GROUP BY s.id, s.name, s.type - grupuje po statku");
        System.out.println("   - COUNT(p), SUM(p.bounty) - agregaty dla każdej grupy");
        System.out.println("   - HAVING COUNT(p) >= 2 - filtr PO agregacji (min. 2 piratów)");
        System.out.println("   - WHERE vs HAVING: WHERE filtruje PRZED, HAVING PO agregacji");
    }

    // ========================================================================
    // ROZWIĄZANIE 6: Criteria API - dynamiczne filtry
    // ========================================================================
    private static void exercise6Solution() {
        CriteriaBuilder cb = em.getCriteriaBuilder();
        CriteriaQuery<Pirate> cq = cb.createQuery(Pirate.class);
        Root<Pirate> pirate = cq.from(Pirate.class);

        // Warunek 1: nazwa zawiera 'a' (case insensitive)
        Predicate nameLike = cb.like(
            cb.lower(pirate.get("name")),  // LOWER(name)
            "%a%"                           // LIKE '%a%'
        );

        // Warunek 2: bounty >= 30,000
        Predicate minBounty = cb.greaterThanOrEqualTo(
            pirate.get("bounty"),
            new BigDecimal("30000")
        );

        // Łączymy warunki przez AND
        cq.where(cb.and(nameLike, minBounty));

        // Sortowanie malejące po bounty
        cq.orderBy(cb.desc(pirate.get("bounty")));

        List<Pirate> results = em.createQuery(cq).getResultList();

        System.out.println("📋 Piraci (nazwa zawiera 'a', bounty >= 30,000):");
        results.forEach(p ->
                System.out.printf("  - %s: $%s%n", p.getName(), p.getBounty()));

        System.out.println("\n💡 Wyjaśnienie:");
        System.out.println("   - CriteriaBuilder cb - fabryka elementów zapytania");
        System.out.println("   - Root<Pirate> pirate - odpowiednik FROM Pirate p");
        System.out.println("   - cb.like(cb.lower(...), pattern) - LIKE case insensitive");
        System.out.println("   - cb.greaterThanOrEqualTo(...) - warunek >=");
        System.out.println("   - cb.and(...) - łączenie warunków");
        System.out.println("   - cb.desc(...) - ORDER BY ... DESC");
        System.out.println("\n   Odpowiednik JPQL:");
        System.out.println("   SELECT p FROM Pirate p");
        System.out.println("   WHERE LOWER(p.name) LIKE '%a%' AND p.bounty >= 30000");
        System.out.println("   ORDER BY p.bounty DESC");
    }

