package pl.przemekzagorski.training.jpa.dto;

import java.math.BigDecimal;

/**
 * DTO dla projekcji pirata - tylko potrzebne pola.
 *
 * Używane z SELECT NEW w JPQL:
 * SELECT NEW pl.przemekzagorski.training.jpa.dto.PirateDTO(p.name, p.rank, p.bounty)
 * FROM Pirate p
 *
 * Zalety DTO:
 * - Mniej danych przesyłanych z bazy
 * - Type-safe (nie Object[])
 * - Immutable (record)
 * - Łatwe do serializacji (JSON)
 */
public record PirateDTO(
    String name,
    String rank,
    BigDecimal bounty
) {
    /**
     * Konstruktor wymagany przez JPQL SELECT NEW.
     * Musi być publiczny i pasować do argumentów w zapytaniu.
     */
    public PirateDTO {
        // record automatycznie generuje konstruktor
    }

    @Override
    public String toString() {
        return String.format("PirateDTO{name='%s', rank='%s', bounty=%s}", name, rank, bounty);
    }
}

package pl.przemekzagorski.training.jpa.dto;

/**
 * DTO dla podsumowania statku - agregacja.
 *
 * Używane do raportów:
 * SELECT NEW ShipSummaryDTO(s.name, s.type, COUNT(p), SUM(p.bounty))
 * FROM Ship s LEFT JOIN s.crew p
 * GROUP BY s.id, s.name, s.type
 */
public record ShipSummaryDTO(
    String shipName,
    String shipType,
    Long crewCount,
    java.math.BigDecimal totalBounty
) {
    @Override
    public String toString() {
        return String.format("ShipSummary{ship='%s', type='%s', crew=%d, totalBounty=%s}",
            shipName, shipType, crewCount, totalBounty);
    }
}

package pl.przemekzagorski.training.jpa.entity;

import jakarta.persistence.*;
import java.math.BigDecimal;

/**
 * Encja wyspy - dla demonstracji zapytań.
 */
@Entity
@Table(name = "islands")
public class Island {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, length = 100)
    private String name;

    @Column(length = 200)
    private String location;

    @Column(name = "has_treasure")
    private Boolean hasTreasure;

    @Column(name = "treasure_value", precision = 15, scale = 2)
    private BigDecimal treasureValue;

    public Island() {
    }

    /**
     * Konstruktor uproszczony - zakłada że wyspa ma skarb.
     */
    public Island(String name, String location, BigDecimal treasureValue) {
        this(name, location, true, treasureValue);
    }

    public Island(String name, String location, boolean hasTreasure, BigDecimal treasureValue) {
        this.name = name;
        this.location = location;
        this.hasTreasure = hasTreasure;
        this.treasureValue = treasureValue;
    }

    // Gettery i Settery
    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }

    public String getName() { return name; }
    public void setName(String name) { this.name = name; }

    public String getLocation() { return location; }
    public void setLocation(String location) { this.location = location; }

    public Boolean getHasTreasure() { return hasTreasure; }
    public void setHasTreasure(Boolean hasTreasure) { this.hasTreasure = hasTreasure; }

    public BigDecimal getTreasureValue() { return treasureValue; }
    public void setTreasureValue(BigDecimal treasureValue) { this.treasureValue = treasureValue; }

    @Override
    public String toString() {
        return String.format("Island{id=%d, name='%s', hasTreasure=%s, treasureValue=%s}",
            id, name, hasTreasure, treasureValue);
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Island island)) return false;
        return id != null && id.equals(island.id);
    }

    @Override
    public int hashCode() {
        return getClass().hashCode();
    }
}

package pl.przemekzagorski.training.jpa.entity;

import jakarta.persistence.*;
import java.math.BigDecimal;
import java.time.LocalDate;

/**
 * Encja pirata - rozbudowana wersja z Named Queries.
 *
 * Named Queries są prekompilowane przy starcie aplikacji,
 * co daje lepszą wydajność i wczesne wykrywanie błędów.
 */
@Entity
@Table(name = "pirates")
@NamedQueries({
    @NamedQuery(
        name = "Pirate.findAll",
        query = "SELECT p FROM Pirate p"
    ),
    @NamedQuery(
        name = "Pirate.findByRank",
        query = "SELECT p FROM Pirate p WHERE p.rank = :rank"
    ),
    @NamedQuery(
        name = "Pirate.findByBountyGreaterThan",
        query = "SELECT p FROM Pirate p WHERE p.bounty > :minBounty ORDER BY p.bounty DESC"
    ),
    @NamedQuery(
        name = "Pirate.findWithShip",
        query = "SELECT p FROM Pirate p JOIN FETCH p.ship WHERE p.id = :id"
    ),
    @NamedQuery(
        name = "Pirate.countByRank",
        query = "SELECT p.rank, COUNT(p) FROM Pirate p GROUP BY p.rank"
    )
})
public class Pirate {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, length = 100)
    private String name;

    @Column(length = 100)
    private String nickname;

    @Column(length = 50)
    private String rank;

    @Column(precision = 12, scale = 2)
    private BigDecimal bounty;

    @Column(name = "joined_at")
    private LocalDate joinedAt;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "ship_id")
    private Ship ship;

    @Version
    private Long version;

    public Pirate() {
    }

    public Pirate(String name, String rank, BigDecimal bounty) {
        this.name = name;
        this.rank = rank;
        this.bounty = bounty;
        this.joinedAt = LocalDate.now();
    }

    public Pirate(String name, String nickname, String rank, BigDecimal bounty) {
        this(name, rank, bounty);
        this.nickname = nickname;
    }

    // Gettery i Settery
    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }

    public String getName() { return name; }
    public void setName(String name) { this.name = name; }

    public String getNickname() { return nickname; }
    public void setNickname(String nickname) { this.nickname = nickname; }

    public String getRank() { return rank; }
    public void setRank(String rank) { this.rank = rank; }

    public BigDecimal getBounty() { return bounty; }
    public void setBounty(BigDecimal bounty) { this.bounty = bounty; }

    public LocalDate getJoinedAt() { return joinedAt; }
    public void setJoinedAt(LocalDate joinedAt) { this.joinedAt = joinedAt; }

    public Ship getShip() { return ship; }
    public void setShip(Ship ship) { this.ship = ship; }

    public Long getVersion() { return version; }
    public void setVersion(Long version) { this.version = version; }

    @Override
    public String toString() {
        return String.format("Pirate{id=%d, name='%s', rank='%s', bounty=%s}",
            id, name, rank, bounty);
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Pirate pirate)) return false;
        return id != null && id.equals(pirate.id);
    }

    @Override
    public int hashCode() {
        return getClass().hashCode();
    }
}

package pl.przemekzagorski.training.jpa.entity;

import jakarta.persistence.*;
import java.util.ArrayList;
import java.util.List;

/**
 * Encja statku - z relacją do piratów.
 */
@Entity
@Table(name = "ships")
@NamedQueries({
    @NamedQuery(
        name = "Ship.findAll",
        query = "SELECT s FROM Ship s"
    ),
    @NamedQuery(
        name = "Ship.findWithCrew",
        query = "SELECT DISTINCT s FROM Ship s LEFT JOIN FETCH s.crew WHERE s.id = :id"
    ),
    @NamedQuery(
        name = "Ship.findByType",
        query = "SELECT s FROM Ship s WHERE s.type = :type"
    )
})
public class Ship {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false, length = 100)
    private String name;

    @Column(length = 50)
    private String type;

    @Column
    private Integer cannons;

    @Column(name = "crew_capacity")
    private Integer crewCapacity;

    @OneToMany(mappedBy = "ship", cascade = CascadeType.ALL, fetch = FetchType.LAZY)
    private List<Pirate> crew = new ArrayList<>();

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "home_island_id")
    private Island homePort;

    public Ship() {
    }

    public Ship(String name, String type, Integer cannons) {
        this.name = name;
        this.type = type;
        this.cannons = cannons;
    }

    // Metody pomocnicze
