package pl.przemekzagorski.training.springdata.entity;

import jakarta.persistence.*;
import jakarta.validation.constraints.*;
import java.math.BigDecimal;
import java.util.Objects;

/**
 * Encja Pirate - kompletny przykład encji JPA dla Spring Data.
 *
 * Zawiera:
 * - @Version (optimistic locking)
 * - Bean Validation (@NotBlank, @Positive, etc.)
 * - Poprawne equals/hashCode
 * - Relacja @ManyToOne
 */
@Entity
@Table(name = "pirates")
public class Pirate {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Version
    private Long version;

    @NotBlank(message = "Imię pirata jest wymagane")
    @Size(min = 2, max = 100, message = "Imię musi mieć 2-100 znaków")
    @Column(nullable = false, length = 100)
    private String name;

    @Size(max = 100, message = "Przydomek może mieć max 100 znaków")
    @Column(length = 100)
    private String nickname;

    @NotBlank(message = "Ranga jest wymagana")
    @Column(nullable = false, length = 50)
    private String rank;

    @NotNull(message = "Bounty jest wymagane")
    @PositiveOrZero(message = "Bounty nie może być ujemne")
    @Column(nullable = false, precision = 15, scale = 2)
    private BigDecimal bounty;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "ship_id")
    private Ship ship;

    // Konstruktory
    public Pirate() {}

    public Pirate(String name, String rank, BigDecimal bounty) {
        this.name = name;
        this.rank = rank;
        this.bounty = bounty;
    }

    // Gettery i Settery
    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }

    public Long getVersion() { return version; }

    public String getName() { return name; }
    public void setName(String name) { this.name = name; }

    public String getNickname() { return nickname; }
    public void setNickname(String nickname) { this.nickname = nickname; }

    public String getRank() { return rank; }
    public void setRank(String rank) { this.rank = rank; }

    public BigDecimal getBounty() { return bounty; }
    public void setBounty(BigDecimal bounty) { this.bounty = bounty; }

    public Ship getShip() { return ship; }
    public void setShip(Ship ship) { this.ship = ship; }

    // equals/hashCode oparte na ID - bezpieczne dla JPA
    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Pirate pirate = (Pirate) o;
        return id != null && Objects.equals(id, pirate.id);
    }

    @Override
    public int hashCode() {
        return getClass().hashCode();
    }

    @Override
    public String toString() {
        return String.format("Pirate{id=%d, name='%s', rank='%s', bounty=%s, version=%d}",
                id, name, rank, bounty, version);
    }
}

package pl.przemekzagorski.training.springdata.entity;

import jakarta.persistence.*;
import jakarta.validation.constraints.*;
import java.util.ArrayList;
import java.util.List;
import java.util.Objects;

/**
 * Encja Ship - przykład encji z relacją @OneToMany.
 */
@Entity
@Table(name = "ships")
public class Ship {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Version
    private Long version;

    @NotBlank(message = "Nazwa statku jest wymagana")
    @Size(min = 2, max = 100, message = "Nazwa musi mieć 2-100 znaków")
    @Column(nullable = false, length = 100)
    private String name;

    @Size(max = 50, message = "Typ może mieć max 50 znaków")
    @Column(length = 50)
    private String type;

    @Min(value = 0, message = "Liczba dział nie może być ujemna")
    @Max(value = 200, message = "Maksymalnie 200 dział")
    @Column
    private Integer cannons;

    @OneToMany(mappedBy = "ship", cascade = CascadeType.ALL, orphanRemoval = true)
    private List<Pirate> crew = new ArrayList<>();

    // Konstruktory
    public Ship() {}

    public Ship(String name, String type, Integer cannons) {
        this.name = name;
        this.type = type;
        this.cannons = cannons;
    }

    // Metody pomocnicze do zarządzania relacją
    public void addCrewMember(Pirate pirate) {
        crew.add(pirate);
        pirate.setShip(this);
    }

    public void removeCrewMember(Pirate pirate) {
        crew.remove(pirate);
        pirate.setShip(null);
    }

    // Gettery i Settery
    public Long getId() { return id; }
    public void setId(Long id) { this.id = id; }

    public Long getVersion() { return version; }

    public String getName() { return name; }
    public void setName(String name) { this.name = name; }

    public String getType() { return type; }
    public void setType(String type) { this.type = type; }

    public Integer getCannons() { return cannons; }
    public void setCannons(Integer cannons) { this.cannons = cannons; }

    public List<Pirate> getCrew() { return crew; }
    public void setCrew(List<Pirate> crew) { this.crew = crew; }

    // equals/hashCode
    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Ship ship = (Ship) o;
        return id != null && Objects.equals(id, ship.id);
    }

    @Override
    public int hashCode() {
        return getClass().hashCode();
    }

    @Override
    public String toString() {
        return String.format("Ship{id=%d, name='%s', type='%s', cannons=%d}",
                id, name, type, cannons);
    }
}

package pl.przemekzagorski.training.springdata.repository;

import org.springframework.data.jpa.repository.EntityGraph;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Modifying;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.transaction.annotation.Transactional;
import pl.przemekzagorski.training.springdata.entity.Pirate;

import java.math.BigDecimal;
import java.util.List;
import java.util.Optional;

/**
 * Repozytorium piratów - pokazuje pełną moc Spring Data JPA.
 *
 * Rozszerzając JpaRepository<Pirate, Long> otrzymujesz ZA DARMO:
 * - save(entity), saveAll(entities)
 * - findById(id), findAll(), findAllById(ids)
 * - count(), existsById(id)
 * - delete(entity), deleteById(id), deleteAll()
 * - i wiele więcej!
 *
 * Dodatkowo możesz definiować własne metody:
 * - Query Methods (nazwy metod jako zapytania)
 * - @Query (JPQL lub native SQL)
 */
public interface PirateRepository extends JpaRepository<Pirate, Long> {

    // ==========================================
    // QUERY METHODS - Zapytania z nazw metod
    // ==========================================

    /**
     * Znajduje piratów według rangi.
     * Spring generuje: SELECT * FROM pirates WHERE rank = ?
     */
    List<Pirate> findByRank(String rank);

    /**
     * Znajduje piratów według nazwy (case insensitive).
     * Spring generuje: SELECT * FROM pirates WHERE LOWER(name) = LOWER(?)
     */
    List<Pirate> findByNameIgnoreCase(String name);

    /**
     * Znajduje piratów z bounty większym niż podana wartość.
     * Sortuje malejąco po bounty.
     */
    List<Pirate> findByBountyGreaterThanOrderByBountyDesc(BigDecimal amount);

    /**
     * Znajduje piratów z bounty w podanym zakresie.
     */
    List<Pirate> findByBountyBetween(BigDecimal min, BigDecimal max);

    /**
     * Znajduje piratów których imię zawiera podany tekst.
     * Spring generuje: SELECT * FROM pirates WHERE name LIKE '%?%'
     */
    List<Pirate> findByNameContaining(String namePart);

    /**
     * Znajduje piratów według rangi i minimalnego bounty.
     */
    List<Pirate> findByRankAndBountyGreaterThan(String rank, BigDecimal minBounty);

    /**
     * Znajduje piratów bez statku.
     */
    List<Pirate> findByShipIsNull();

    /**
     * Zlicza piratów według rangi.
     */
    long countByRank(String rank);

    /**
     * Sprawdza czy istnieje pirat o podanej nazwie.
     */
    boolean existsByName(String name);

    /**
     * Znajduje top 3 piratów z największym bounty.
     */
    List<Pirate> findTop3ByOrderByBountyDesc();

    /**
     * Znajduje pierwszego pirata o podanej randze.
     */
    Optional<Pirate> findFirstByRank(String rank);

    // ==========================================
    // @QUERY - Własne zapytania JPQL
    // ==========================================

    /**
     * Znajduje pirata z największym bounty.
     */
    @Query("SELECT p FROM Pirate p WHERE p.bounty = (SELECT MAX(p2.bounty) FROM Pirate p2)")
    Optional<Pirate> findMostWanted();

    /**
     * Znajduje piratów według rangi z JOIN FETCH na ship.
     * Rozwiązuje problem N+1!
     */
    @Query("SELECT p FROM Pirate p LEFT JOIN FETCH p.ship WHERE p.rank = :rank")
    List<Pirate> findByRankWithShip(@Param("rank") String rank);

    /**
     * Oblicza sumę bounty dla wszystkich piratów.
     */
    @Query("SELECT COALESCE(SUM(p.bounty), 0) FROM Pirate p")
    BigDecimal sumAllBounties();

    /**
     * Średnie bounty według rangi.

*/
    @Query("SELECT COALESCE(SUM(p.bounty), 0) FROM Pirate p")
    BigDecimal sumAllBounties();

    /**
     * Średnie bounty według rangi.
     */
    @Query("SELECT p.rank, AVG(p.bounty) FROM Pirate p GROUP BY p.rank")
    List<Object[]> avgBountyByRank();

    // ==========================================
    // @MODIFYING - Zapytania modyfikujące
    // ==========================================

    /**
     * Zwiększa bounty wszystkich piratów o podany procent.
     * WAŻNE: @Modifying + @Transactional
     */
    @Modifying
    @Transactional
    @Query("UPDATE Pirate p SET p.bounty = p.bounty * (1 + :percent/100) WHERE p.rank = :rank")
    int increaseBountyForRank(@Param("rank") String rank, @Param("percent") BigDecimal percent);

    /**
     * Usuwa piratów z bounty = 0.
     */
    @Modifying
    @Transactional
    @Query("DELETE FROM Pirate p WHERE p.bounty = 0")
    int deleteZeroBountyPirates();

    // ==========================================
    // ENTITY GRAPH - Eager loading
    // ==========================================

    /**
     * Znajduje pirata po ID z załadowanym statkiem.
     * Alternatywa dla JOIN FETCH.
     */
    @EntityGraph(attributePaths = {"ship"})
    Optional<Pirate> findWithShipById(Long id);

    /**
     * Znajduje wszystkich piratów z załadowanymi statkami.
     */
    @EntityGraph(attributePaths = {"ship"})
    List<Pirate> findAllWithShipBy();
}

package pl.przemekzagorski.training.springdata.repository;

import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import pl.przemekzagorski.training.springdata.entity.Ship;

import java.util.List;
import java.util.Optional;

/**
 * Repozytorium statków.
 */
public interface ShipRepository extends JpaRepository<Ship, Long> {

    /**
     * Znajduje statek po nazwie.
     */
    Optional<Ship> findByName(String name);

    /**
     * Znajduje statki według typu.
     */
    List<Ship> findByType(String type);

    /**
     * Znajduje statki z załogą (mające przynajmniej jednego pirata).
     */
    @Query("SELECT DISTINCT s FROM Ship s JOIN s.crew c")
    List<Ship> findShipsWithCrew();

    /**
     * Znajduje statek z całą załogą (JOIN FETCH).
     */
    @Query("SELECT s FROM Ship s LEFT JOIN FETCH s.crew WHERE s.id = :id")
    Optional<Ship> findByIdWithCrew(@Param("id") Long id);

    /**
     * Zlicza piratów na statku.
     */
    @Query("SELECT SIZE(s.crew) FROM Ship s WHERE s.id = :id")
    int countCrewMembers(@Param("id") Long id);
}

package pl.przemekzagorski.training.springdata.service;

import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import pl.przemekzagorski.training.springdata.entity.Pirate;
import pl.przemekzagorski.training.springdata.entity.Ship;
import pl.przemekzagorski.training.springdata.repository.PirateRepository;
import pl.przemekzagorski.training.springdata.repository.ShipRepository;

import java.math.BigDecimal;
import java.util.List;

/**
 * Serwis piratów - warstwa logiki biznesowej.
 *
 * WAŻNE:
 * - @Transactional na poziomie klasy = każda publiczna metoda to osobna transakcja
 * - Wyjątek RuntimeException = automatyczny rollback
 * - Dirty checking działa - nie trzeba wołać save() dla managed entities
 */
@Service
@Transactional
public class PirateService {

    private final PirateRepository pirateRepository;
    private final ShipRepository shipRepository;

    public PirateService(PirateRepository pirateRepository, ShipRepository shipRepository) {
        this.pirateRepository = pirateRepository;
        this.shipRepository = shipRepository;
    }

    /**
     * Rekrutuje pirata do załogi statku.
     */
    public void recruitPirate(Long pirateId, Long shipId) {
        Pirate pirate = pirateRepository.findById(pirateId)
                .orElseThrow(() -> new IllegalArgumentException("Pirat nie istnieje: " + pirateId));

        Ship ship = shipRepository.findById(shipId)
                .orElseThrow(() -> new IllegalArgumentException("Statek nie istnieje: " + shipId));

        // Dirty checking - zmiana zostanie zapisana automatycznie
        pirate.setShip(ship);

        System.out.printf("✅ Pirat %s dołączył do załogi %s%n", pirate.getName(), ship.getName());
    }

    /**
     * Transferuje pirata między statkami.
     * Transakcja obejmuje obie operacje - albo obie się udają, albo żadna.
     */
    public void transferPirate(Long pirateId, Long fromShipId, Long toShipId) {
        Pirate pirate = pirateRepository.findWithShipById(pirateId)
                .orElseThrow(() -> new IllegalArgumentException("Pirat nie istnieje: " + pirateId));

        if (pirate.getShip() == null || !pirate.getShip().getId().equals(fromShipId)) {
            throw new IllegalStateException("Pirat nie jest na statku " + fromShipId);
        }

        Ship toShip = shipRepository.findById(toShipId)
                .orElseThrow(() -> new IllegalArgumentException("Statek docelowy nie istnieje: " + toShipId));

        String fromShipName = pirate.getShip().getName();
        pirate.setShip(toShip);

        System.out.printf("✅ Pirat %s przetransferowany z %s na %s%n",
                pirate.getName(), fromShipName, toShip.getName());
    }

    /**
     * Podnosi bounty kapitanów o określony procent.
     * Używa bulk update dla wydajności.
     */
    public int raiseCaptainBounties(BigDecimal percent) {
        int updated = pirateRepository.increaseBountyForRank("Captain", percent);
        System.out.printf("✅ Podniesiono bounty %d kapitanów o %.0f%%%n", updated, percent);
        return updated;
    }

    /**
     * Znajduje piratów "most wanted" (top 3 bounty).
     */
    @Transactional(readOnly = true)  // Optymalizacja dla read-only
    public List<Pirate> getMostWanted() {
        return pirateRepository.findTop3ByOrderByBountyDesc();
    }

    /**
     * Pobiera statystyki floty.
     */
    @Transactional(readOnly = true)
    public FleetStats getFleetStats() {
        long totalPirates = pirateRepository.count();
        long totalShips = shipRepository.count();
        BigDecimal totalBounty = pirateRepository.sumAllBounties();
        long captains = pirateRepository.countByRank("Captain");

        return new FleetStats(totalPirates, totalShips, totalBounty, captains);
    }

    /**
     * DTO ze statystykami floty.

*/
    public record FleetStats(
            long totalPirates,
            long totalShips,
            BigDecimal totalBounty,
            long captains
    ) {}
}

