 */
public class PerformanceExercisesSolutions {

    private EntityManagerFactory emf;

    public PerformanceExercisesSolutions() {
        this.emf = Persistence.createEntityManagerFactory("advanced-pu");
    }

    /**
     * ════════════════════════════════════════════════════════════════
     * ROZWIĄZANIE 1: Cache L1 w praktyce
     * ════════════════════════════════════════════════════════════════
     */
    public void solution1_cacheL1Verification() {
        System.out.println("=== ROZWIĄZANIE 1: Cache L1 ===\n");

        EntityManager em = emf.createEntityManager();

        try {
            // Najpierw utwórz autora do testów
            em.getTransaction().begin();
            Author testAuthor = new Author("Jack Sparrow");
            em.persist(testAuthor);
            em.getTransaction().commit();
            Long authorId = testAuthor.getId();

            // Wyczyść cache i zacznij od nowa
            em.clear();

            System.out.println(">>> Pobieranie autora 3 razy (obserwuj SQL!):\n");

            // Pierwsze pobranie - idzie do bazy
            System.out.println("1. Pierwsze em.find():");
            Author author1 = em.find(Author.class, authorId);
            System.out.println("   Pobrano: " + author1.getName());

            // Drugie pobranie - z cache L1!
            System.out.println("\n2. Drugie em.find() - Z CACHE (brak SQL!):");
            Author author2 = em.find(Author.class, authorId);
            System.out.println("   Pobrano: " + author2.getName());

            // Trzecie pobranie - również z cache L1!
            System.out.println("\n3. Trzecie em.find() - Z CACHE (brak SQL!

System.out.println("\n2. Drugie em.find() - Z CACHE (brak SQL!):");
            Author author2 = em.find(Author.class, authorId);
            System.out.println("   Pobrano: " + author2.getName());

            // Trzecie pobranie - również z cache L1!
            System.out.println("\n3. Trzecie em.find() - Z CACHE (brak SQL!):");
            Author author3 = em.find(Author.class, authorId);
            System.out.println("   Pobrano: " + author3.getName());

            // Weryfikacja
            boolean cacheWorks = (author1 == author2) && (author2 == author3);
            System.out.println("\n>>> Weryfikacja Cache L1:");
            System.out.println("   author1 == author2: " + (author1 == author2));
            System.out.println("   author2 == author3: " + (author2 == author3));
            System.out.println("   ✅ Cache L1 działa: " + cacheWorks);

        } finally {
            em.close();
        }
    }

    /**
     * ════════════════════════════════════════════════════════════════
     * ROZWIĄZANIE 2: Paginacja kapitanów
     * ════════════════════════════════════════════════════════════════
     */
    public List<Author> getAuthorsPage(EntityManager em, int pageNumber, int pageSize) {
        TypedQuery<Author> query = em.createQuery(
                "SELECT a FROM Author a ORDER BY a.name", Author.class);

        // Oblicz offset: strona 0 → skip 0, strona 1 → skip pageSize, itd.

query.setFirstResult(pageNumber * pageSize);
        query.setMaxResults(pageSize);

        return query.getResultList();
    }

    public long getTotalPages(EntityManager em, int pageSize) {
        Long totalCount = em.createQuery("SELECT COUNT(a) FROM Author a", Long.class)
                .getSingleResult();
        return (long) Math.ceil((double) totalCount / pageSize);
    }

    public void solution2_pagination() {
        System.out.println("\n=== ROZWIĄZANIE 2: Paginacja ===\n");

        EntityManager em = emf.createEntityManager();

        try {
            // Utwórz dane testowe
            em.getTransaction().begin();
            for (int i = 1; i <= 25; i++) {
                em.persist(new Author("Kapitan " + String.format("%02d", i)));
            }
            em.getTransaction().commit();

            int pageSize = 5;

            // Pobierz pierwszą stronę
            System.out.println(">>> Strona 1 (pageNumber=0, pageSize=5):");
            List<Author> page1 = getAuthorsPage(em, 0, pageSize);
            page1.forEach(a -> System.out.println("   - " + a.getName()));

            // Pobierz trzecią stronę
            System.out.println("\n>>> Strona 3 (pageNumber=2, pageSize=5):");
            List<Author> page3 = getAuthorsPage(em, 2, pageSize);
            page3.forEach(a -> System.out.println("   - " + a.getName()));

            // Oblicz całkowitą liczbę stron
            long totalPages = getTotalPages(em, pageSize);
            System.out.println("\n>>> Całkowita liczba stron: " + totalPages);

        } finally {
            em.close();
        }
    }

    /**
     * ════════════════════════════════════════════════════════════════
     * ROZWIĄZANIE 3: Projekcja DTO
     * ════════════════════════════════════════════════════════════════
     */

    // DTO jako record (Java 16+)
    public record AuthorDTO(Long id, String name) {
        @Override
        public String toString() {
            return "AuthorDTO{id=" + id + ", name='" + name + "'}";
        }
    }

    public List<AuthorDTO> getAuthorDTOs(EntityManager em) {
        // SELECT NEW wymaga pełnej ścieżki do klasy DTO
        return em.createQuery(
                        "SELECT NEW pl.przemekzagorski.training.hibernate.PerformanceExercisesSolutions$AuthorDTO(a.id, a.name) FROM Author a",
                        AuthorDTO.class)
                .getResultList();
    }

    public void solution3_projection() {
        System.out.println("\n=== ROZWIĄZANIE 3: Projekcja DTO ===\n");

        EntityManager em = emf.createEntityManager();

        try {
            System.out.println(">>> Porównanie: pełna encja vs DTO\n");

            // Pełna encja - więcej kolumn w SQL
            System.out.println("1. Pobieranie pełnej encji (wszystkie kolumny):");
            List<Author> fullEntities = em.createQuery("SELECT a FROM Author a", Author.class)
                    .setMaxResults(3)
                    .getResultList();
            fullEntities.forEach(a -> System.out.println("   " + a));

            // DTO - tylko id i name
            System.out.println("\n2.

Pobieranie pełnej encji (wszystkie kolumny):");
            List<Author> fullEntities = em.createQuery("SELECT a FROM Author a", Author.class)
                    .setMaxResults(3)
                    .getResultList();
            fullEntities.forEach(a -> System.out.println("   " + a));

            // DTO - tylko id i name
            System.out.println("\n2. Pobieranie DTO (tylko id, name):");

            // Alternatywna składnia bez SELECT NEW (Object[])
            List<Object[]> rawResults = em.createQuery(
                            "SELECT a.id, a.name FROM Author a", Object[].class)
                    .setMaxResults(3)
                    .getResultList();

            for (Object[] row : rawResults) {
                Long id = (Long) row[0];
