                System.out.println("   AuthorDTO{id=" + id + ", name='" + name + "'}");
            }

            System.out.println("\n✅ Korzyści projekcji:");
            System.out.println("   - Mniej danych przesyłanych z bazy");
            System.out.println("   - Brak proxy Hibernate");
            System.out.println("   - Szybsze dla list dropdown, autocomplete");

        } finally {
            em.close();
        }
    }

    /**
     * ════════════════════════════════════════════════════════════════
     * ROZWIĄZANIE 4: Read-only dla raportów
     * ════════════════════════════════════════════════════════════════
     */
    public void solution4_readOnlyMode() {
        System.out.println("\n=== ROZWIĄZANIE 4: Read-only Mode ===\n");

        EntityManager em = emf.createEntityManager();

        try {
            em.getTransaction().begin();

            System.out.println(">>> Pobieranie z hintem readOnly=true:");
            List<Author> readOnlyAuthors = em.createQuery("SELECT a FROM Author a", Author.class)
                    .setHint("org.hibernate.readOnly", true)
                    .setMaxResults(1)
                    .getResultList();

            if (!readOnlyAuthors.isEmpty()) {
                Author author = readOnlyAuthors.get(0);
                String originalName = author.getName();

                System.out.println("   Oryginalna nazwa: " + originalName);

                // Próba modyfikacji
                System.out.println("\n>>> Próba modyfikacji encji read-only:");
                author.setName("ZMIENIONA NAZWA");
                System.out.println("   Ustawiono nazwę na: " + author.getName());

                // Flush - czy zmiana pójdzie do bazy?
                System.out.println("\n>>> Wywołuję em.flush()...");
                em.flush();

                // Sprawdź w bazie
                em.clear(); // wyczyść cache
                Author reloaded = em.find(Author.class, author.getId());
                System.out.println("   Nazwa w bazie: " + reloaded.getName());

                if (reloaded.getName().equals(originalName)) {
                    System.out.println("\n✅ Read-only działa! Zmiana NIE została zapisana.");
                } else {
                    System.out.println("\n⚠️ Uwaga: Zmiana została zapisana (sprawdź konfigurację).

Zmiana NIE została zapisana.");
                } else {
                    System.out.println("\n⚠️ Uwaga: Zmiana została zapisana (sprawdź konfigurację).");
                }
            }

            em.getTransaction().commit();

        } finally {
            em.close();
        }
    }

    /**
     * ════════════════════════════════════════════════════════════════
     * ROZWIĄZANIE 5: Batch processing z flush/clear
     * ════════════════════════════════════════════════════════════════
     */
    public void solution5_batchProcessing() {
        System.out.println("\n=== ROZWIĄZANIE 5: Batch Processing ===\n");

        EntityManager em = emf.createEntityManager();

        int totalRecords = 1000;  // 1000 zamiast 10000 dla szybkości demo
        int batchSize = 100;

        try {
            em.getTransaction().begin();

            long startTime = System.currentTimeMillis();

            System.out.println(">>> Tworzę " + totalRecords + " autorów w batchach po " + batchSize + "...\n");

            for (int i = 1; i <= totalRecords; i++) {
                Author author = new Author("Captain Batch " + i);
                em.persist(author);

                // Co 100 rekordów: flush + clear
                if (i % batchSize == 0) {
                    em.flush();  // wyślij INSERT do bazy
                    em.clear(); // wyczyść Persistence Context (zwolnij pamięć!)

                    System.out.println("   Batch " + (i / batchSize) + "/" + (totalRecords / batchSize) +
                            " - flush+clear (zapisano " + i + " rekordów)");
                }
            }

            em.getTransaction().commit();

            long endTime = System.currentTimeMillis();
            System.out.println("\n✅ Zakończono w " + (endTime - startTime) + " ms");
            System.out.println("   Bez flush/clear: OutOfMemoryError przy dużych zbiorach!");

        } finally {
            em.close();
        }
    }

    /**
     * Uruchom wszystkie rozwiązania.
     */
    public static void main(String[] args) {
        PerformanceExercisesSolutions solutions = new PerformanceExercisesSolutions();

        try {
            solutions.solution1_cacheL1Verification();
            solutions.solution2_pagination();
            solutions.solution3_projection();
