        em.getTransaction().begin();
        for (int i = 1; i <= 30; i++) {
            em.persist(new Author("Captain " + String.format("%02d", i)));
        }
        em.getTransaction().commit();
        em.clear();

        int pageSize = 10;

        // When - pobierz wszystkie strony
