package pl.przemekzagorski.training.springdata.advanced.service;

import jakarta.persistence.EntityManager;
import jakarta.persistence.PersistenceContext;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.ApplicationContext;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Propagation;
import org.springframework.transaction.annotation.Transactional;
import pl.przemekzagorski.training.springdata.advanced.entity.Pirate;
import pl.przemekzagorski.training.springdata.advanced.repository.PirateRepository;

import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;

/**
 * 🎯 Serwis demonstracyjny dla Batch Processing.
 *
 * KONCEPCJA:
 * - Batch Processing = grupowanie operacji INSERT/UPDATE w batche
 * - Zamiast 1000 pojedynczych INSERT, wykonuje 20 batchy po 50 INSERT
 * - Wymaga flush() i clear() co N rekordów
 *
 * KONFIGURACJA:
 * - hibernate.jdbc.batch_size=50 (w application.yml)
 * - hibernate.order_inserts=true
 * - hibernate.order_updates=true
 *
 * KORZYŚCI:
 * - Znacznie szybszy import dużej ilości danych
 * - Mniejsze zużycie pamięci (clear() zwalnia Session cache)
 * - Mniejsze obciążenie bazy danych
 *
 * RÓŻNICA vs Pure JPA:
 * - Identyczna technika (flush/clear)
 * - Spring: @Transactional zamiast ręcznego zarządzania transakcją
 */
@Service
public class BatchProcessingService {

    private static final Logger log = LoggerFactory.getLogger(BatchProcessingService.class);
    private static final int BATCH_SIZE = 50;

    @PersistenceContext
    private EntityManager entityManager;

    private final PirateRepository pirateRepository;

    @Autowired
    private ApplicationContext applicationContext;

    public BatchProcessingService(PirateRepository pirateRepository) {
        this.pirateRepository = pirateRepository;
    }

    /**
     * Pobiera proxy tego serwisu, aby wywołania @Transactional działały poprawnie.
     * Rozwiązuje problem self-invocation w Spring AOP.
     */
    private BatchProcessingService getSelf() {
        return applicationContext.getBean(BatchProcessingService.class);
    }

    /**
     * Demo 1: Import bez batch processing (WOLNY).
     *
     * PROBLEM:
     * - Wszystkie encje trzymane w Session cache
     * - Duże zużycie pamięci
     * - Wolniejsze INSERT (pojedyncze)
     */
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void importWithoutBatch(int count) {
        log.info("=== DEMO: Import BEZ batch processing ===");
        long start = System.currentTimeMillis();

        List<Pirate> pirates = new ArrayList<>();
        for (int i = 0; i < count; i++) {
            Pirate pirate = new Pirate(
                "Pirate " + i,
                "Sailor",
                BigDecimal.valueOf(1000 + i)
            );
            pirates.add(pirate);
        }

        pirateRepository.saveAll(pirates);

        long end = System.currentTimeMillis();
        log.info("✅ Zaimportowano {} piratów w {} ms (BEZ batch)", count, end - start);
    }

    /**
     * Demo 2: Import z batch processing (SZYBKI).

*
     * ROZWIĄZANIE:
     * - flush() co BATCH_SIZE rekordów - wysyła batch do bazy
     * - clear() co BATCH_SIZE rekordów - zwalnia Session cache
     * - Hibernate grupuje INSERT w batche
     *
     * KLUCZOWE:
     * - Używamy persist() zamiast merge() (szybsze dla nowych encji)
     * - SEQUENCE generuje ID automatycznie (allocationSize=50)
     * - flush() + clear() co BATCH_SIZE zwalnia pamięć
     */
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void importWithBatch(int count) {
        log.info("=== DEMO: Import Z batch processing ===");
        long start = System.currentTimeMillis();

        for (int i = 0; i < count; i++) {
            Pirate pirate = new Pirate(
                "BatchPirate " + i,
                "Sailor",
                BigDecimal.valueOf(1000 + i)
            );
            entityManager.persist(pirate);  // ✅ persist() zamiast merge()!

            // Co BATCH_SIZE rekordów: flush + clear
            if ((i + 1) % BATCH_SIZE == 0) {
                entityManager.flush();  // Wyślij batch do bazy
                entityManager.clear();  // Wyczyść Session cache
                log.debug("Batch {} wysłany ({} rekordów)", (i + 1) / BATCH_SIZE, BATCH_SIZE);
            }
        }

        // Ostatni batch (jeśli count nie jest wielokrotnością BATCH_SIZE)
        entityManager.flush();
        entityManager.clear();

        long end = System.currentTimeMillis();
        log.info("✅ Zaimportowano {} piratów w {} ms (Z batch)", count, end - start);
    }

    /**
     * Demo 3: Porównanie wydajności.
     *
     * OBSERWUJ:
     * - Różnicę w czasie wykonania
     * - Logi SQL (batche vs pojedyncze INSERT)
     *
     * UWAGA:
     * - NIE ma @Transactional - każda metoda ma swoją transakcję
     * - Czyszczenie bazy między testami dla uczciwego porównania
     */
    public void comparePerformance() {
        log.info("=== DEMO: Porównanie wydajności ===");

        int testSize = 1000;

        // Test 1: Bez batch
        log.info("Test 1: Import BEZ batch processing...");
        long start1 = System.currentTimeMillis();
        getSelf().importWithoutBatch(testSize);  // ✅ Wywołanie przez proxy
        long time1 = System.currentTimeMillis() - start1;

        // Wyczyść bazę przed drugim testem
        getSelf().cleanupTestData();  // ✅ Wywołanie przez proxy

        // Test 2: Z batch
        log.info("Test 2: Import Z batch processing...");
        long start2 = System.currentTimeMillis();
        getSelf().importWithBatch(testSize);  // ✅ Wywołanie przez proxy
        long time2 = System.currentTimeMillis() - start2;

        log.info("=== WYNIKI ===");
        log.info("Bez batch: {} ms", time1);
        log.info("Z batch: {} ms", time2);
        log.info("Przyspieszenie: {}x", (double) time1 / time2);
    }

    /**
     * Pomocnicza metoda do czyszczenia danych testowych.
     */
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void cleanupTestData() {
        log.debug("Czyszczenie danych testowych...");
        pirateRepository.deleteAll();
    }

    /**
     * Demo 4: Update w batch.

*/
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void cleanupTestData() {
        log.debug("Czyszczenie danych testowych...");
        pirateRepository.deleteAll();
    }

    /**
     * Demo 4: Update w batch.
     */
    @Transactional
    public void updateInBatch() {
        log.info("=== DEMO: Update w batch ===");

        List<Pirate> pirates = pirateRepository.findByRank("Sailor");
        log.info("Znaleziono {} marynarzy do aktualizacji", pirates.size());

        long start = System.currentTimeMillis();

        for (int i = 0; i < pirates.size(); i++) {
            Pirate pirate = pirates.get(i);
            pirate.setBounty(pirate.getBounty().add(BigDecimal.valueOf(100)));

            if (i > 0 && i % BATCH_SIZE == 0) {
                entityManager.flush();
                entityManager.clear();
            }
        }

        entityManager.flush();

        long end = System.currentTimeMillis();
        log.info("✅ Zaktualizowano {} piratów w {} ms", pirates.size(), end - start);
    }
}

package pl.przemekzagorski.training.springdata.advanced.service;

import jakarta.persistence.EntityManager;
import org.hibernate.Session;
import org.hibernate.SessionFactory;
import org.hibernate.stat.Statistics;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.PlatformTransactionManager;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.transaction.support.TransactionTemplate;
import pl.przemekzagorski.training.springdata.advanced.entity.Pirate;
import pl.przemekzagorski.training.springdata.advanced.repository.PirateRepository;

import java.util.List;

/**
 * 🎯 Serwis demonstracyjny dla Cache L2 (Hibernate Second Level Cache).
 *
 * KONCEPCJA Cache L2:
 * - Cache L1 (Session Cache) - automatyczny, per-session
 * - Cache L2 (SessionFactory Cache) - współdzielony między sesjami
 * - Cache L2 działa między transakcjami!
 *
 * KORZYŚCI:
 * - Mniej zapytań do bazy
 * - Szybsze odczyty
 * - Mniejsze obciążenie bazy danych
 *
 * KONFIGURACJA:
 * - @Cacheable na encji
 * - @Cache(usage = CacheConcurrencyStrategy.READ_WRITE)
 * - ehcache.xml z konfiguracją regionów
 * - application.yml: hibernate.cache.use_second_level_cache=true
 */
@Service
public class CacheL2DemoService {

    private static final Logger log = LoggerFactory.getLogger(CacheL2DemoService.class);

    private final PirateRepository pirateRepository;
    private final TransactionTemplate transactionTemplate;
    private final SessionFactory sessionFactory;

    public CacheL2DemoService(PirateRepository pirateRepository,
                              PlatformTransactionManager transactionManager,
                              EntityManager entityManager) {
        this.pirateRepository = pirateRepository;
        this.transactionTemplate = new TransactionTemplate(transactionManager);
        this.transactionTemplate.setReadOnly(true);
        this.sessionFactory = entityManager.unwrap(Session.class).getSessionFactory();
    }

    /**
     * Demo 1: Entity Cache L2 - pobieranie encji po ID.
     *
     * OBSERWUJ w logach:
     * - Transakcja 1: SELECT z bazy (cache miss)
     * - Transakcja 2: brak SELECT (cache hit!)
     *
     * WAŻNE: Cache L2 działa MIĘDZY transakcjami!
     * Używamy TransactionTemplate do tworzenia osobnych transakcji.
     */
    public void demonstrateCacheHit() {
        log.info("=== DEMO: Entity Cache L2 (findById) ===");
        log.info("Entity Cache cachuje POJEDYNCZE ENCJE po ich ID");
        log.info("");

        // Wyczyść cache i statystyki przed demo
        sessionFactory.getCache().evictAllRegions();
        sessionFactory.getStatistics().clear();

        // ===== TRANSAKCJA 1 =====
        log.info("▶ TRANSAKCJA #1: findById(1)");

        Pirate pirate1 = transactionTemplate.execute(status ->
            pirateRepository.findById(1L).orElseThrow()
        );

        Statistics stats1 = sessionFactory.getStatistics();
        log.info("  Wynik: {} ", pirate1.getName());
        log.info("  Cache: MISS=1, HIT=0 → SQL wykonany");
        log.info("  Hit Ratio tej transakcji: 0% (encja nie była w cache)");

        // ===== TRANSAKCJA 2 =====
        log.info("");
        log.info("▶ TRANSAKCJA #2: findById(1)");

        // Zapisz statystyki PRZED drugą transakcją
        long hitsBefore = stats1.getSecondLevelCacheHitCount();

        Pirate pirate2 = transactionTemplate.execute(status ->
            pirateRepository.findById(1L).orElseThrow()
        );

        Statistics stats2 = sessionFactory.getStatistics();
        long hitsAfter = stats2.getSecondLevelCacheHitCount();

        log.info("  Wynik: {} ", pirate2.getName());
        log.info("  Cache: MISS=0, HIT=1 → SQL NIE wykonany!

");
        log.info("  Hit Ratio tej transakcji: 100% (encja była w cache!) ✅");

        // ===== PODSUMOWANIE =====
        log.info("");
        log.info("┌─────────────────────────────────────────────────────┐");
        log.info("│ PODSUMOWANIE (suma 2 transakcji)                    │");
        log.info("│ Hits: {}  Misses: {}  Puts: {}                        │",
            stats2.getSecondLevelCacheHitCount(),
            stats2.getSecondLevelCacheMissCount(),
            stats2.getSecondLevelCachePutCount());
        log.info("│ Łączny Hit Ratio: {}%                                │",
            calculateHitRatio(stats2.getSecondLevelCacheHitCount(), stats2.getSecondLevelCacheMissCount()));
        log.info("│                                                     │");
        log.info("│ Transakcja #1: 0% (cold cache)                      │");
        log.info("│ Transakcja #2: 100% (warm cache) ✅                 │");
        log.info("└─────────────────────────────────────────────────────┘");
    }

    private String calculateHitRatio(long hits, long misses) {
        if (hits + misses == 0) return "N/A";
        return String.format("%.0f", (double) hits / (hits + misses) * 100);
    }

    /**
     * Demo 2: Statystyki cache.
     * 
     * Pokazuje:
     * - Ile razy użyto cache (hit)
     * - Ile razy cache nie miał danych (miss)
     * - Hit ratio (% trafień)
     */
    public void printCacheStatistics() {
        Statistics stats = sessionFactory.getStatistics();

        log.info("=== STATYSTYKI CACHE L2 ===");
        log.info("Second Level Cache Hits: {}", stats.getSecondLevelCacheHitCount());
        log.info("Second Level Cache Misses: {}", stats.getSecondLevelCacheMissCount());
        log.info("Second Level Cache Puts: {}", stats.getSecondLevelCachePutCount());

        long hits = stats.getSecondLevelCacheHitCount();
        long misses = stats.getSecondLevelCacheMissCount();
        if (hits + misses > 0) {
            double hitRatio = (double) hits / (hits + misses) * 100;
            log.info("Hit Ratio: {}%", String.format("%.2f", hitRatio));
        } else {
            log.info("Hit Ratio: N/A (brak operacji cache)");
        }

        log.info("Query Cache Hits: {}", stats.getQueryCacheHitCount());
        log.info("Query Cache Misses: {}", stats.getQueryCacheMissCount());
    }

    /**
     * Demo 3: Czyszczenie cache.
     */
    @Transactional
    public void clearCache() {
        log.info("=== Czyszczenie Cache L2 ===");
        sessionFactory.getCache().evictAllRegions();
        log.info("✅ Cache wyczyszczony");
    }

    /**
     * Demo 4: Query Cache.
     * 
     * Używa metody findByRankCacheable() z @QueryHints.
     *
     * WAŻNE - Query Cache to DWA POZIOMY:
     * 1. Query Cache - cachuje wyniki zapytania (lista ID encji)
     * 2.

* 
     * Używa metody findByRankCacheable() z @QueryHints.
     *
     * WAŻNE - Query Cache to DWA POZIOMY:
     * 1. Query Cache - cachuje wyniki zapytania (lista ID encji)
     * 2. Entity Cache (L2) - cachuje same encje
     *
     * Przy drugim wywołaniu:
     * - Query Cache HIT = mamy listę ID w cache
     * - Entity Cache HIT = encje też są w cache (nie trzeba pobierać z bazy)
     */
    public void demonstrateQueryCache() {
        log.info("=== DEMO: Query Cache ===");
        log.info("Query Cache cachuje WYNIKI ZAPYTAŃ (listę ID), encje są w Entity Cache L2");
        log.info("");

        // Wyczyść CAŁY cache żeby demo działało niezależnie od poprzednich operacji
        sessionFactory.getCache().evictAllRegions();
        sessionFactory.getStatistics().clear();

        // ===== TRANSAKCJA 1 =====
        log.info("▶ TRANSAKCJA #1: findByRankCacheable('Captain')");

        List<Pirate> captains1 = transactionTemplate.execute(status ->
            pirateRepository.findByRankCacheable("Captain")
        );

        Statistics stats1 = sessionFactory.getStatistics();
        log.info("  Wynik: {} kapitanów", captains1.size());
        log.info("  Query Cache: MISS=1 → SQL wykonany");
        log.info("  Entity Cache: PUT={} (encje zapisane)", stats1.getSecondLevelCachePutCount());
        log.info("  Hit Ratio tej transakcji: 0% (cold cache)");

        // ===== TRANSAKCJA 2 =====
        log.info("");
        log.info("▶ TRANSAKCJA #2: findByRankCacheable('Captain')");

        List<Pirate> captains2 = transactionTemplate.execute(status ->
            pirateRepository.findByRankCacheable("Captain")
        );

        Statistics stats2 = sessionFactory.getStatistics();
        log.info("  Wynik: {} kapitanów", captains2.size());
        log.info("  Query Cache: HIT=1 → SQL NIE wykonany!");
        log.info("  Hit Ratio tej transakcji: 100% (warm cache) ✅");

        // ===== PODSUMOWANIE =====
        log.info("");
        log.info("┌─────────────────────────────────────────────────────┐");
        log.info("│ PODSUMOWANIE (suma 2 transakcji)                    │");
        log.info("│ Query Cache:  Hits={}  Misses={}  Puts={}             │",
            stats2.getQueryCacheHitCount(),
            stats2.getQueryCacheMissCount(),
            stats2.getQueryCachePutCount());
        log.info("│ Entity Cache: Hits={}  Misses={}  Puts={}             │",
            stats2.getSecondLevelCacheHitCount(),
            stats2.getSecondLevelCacheMissCount(),
            stats2.getSecondLevelCachePutCount());
        log.info("│                                                     │");
        log.info("│ Transakcja #1: 0% (cold cache)                      │");
        log.info("│ Transakcja #2: 100% (warm cache) ✅                 │");
        log.info("└─────────────────────────────────────────────────────┘");
    }
}

package pl.przemekzagorski.training.springdata.advanced.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import pl.przemekzagorski.training.springdata.advanced.entity.Pirate;
import pl.przemekzagorski.training.springdata.advanced.repository.PirateRepository;

/**
 * 🎯 Serwis demonstracyjny dla Paginacji (Pageable i Page<T>).
 *
 * KONCEPCJA:
 * - Pageable - obiekt z parametrami paginacji (strona, rozmiar, sortowanie)
 * - Page<T> - wynik z danymi + metadane (total, totalPages, hasNext, etc.)
 *
 * KORZYŚCI:
 * - Nie ładujemy wszystkich danych naraz
 * - Mniejsze zużycie pamięci
 * - Szybsze zapytania
 * - Lepsze UX (infinite scroll, pagination controls)
 *
 * RÓŻNICA vs Pure JPA:
 * - Pure JPA: setFirstResult(), setMaxResults()
 * - Spring Data: Pageable (czytelniejsze, więcej metadanych)
 */
@Service
@Transactional(readOnly = true)
public class PaginationService {

    private static final Logger log = LoggerFactory.getLogger(PaginationService.class);

    private final PirateRepository pirateRepository;

    public PaginationService(PirateRepository pirateRepository) {
        this.pirateRepository = pirateRepository;
    }

    /**
     * Demo 1: Podstawowa paginacja.
     * 
     * UŻYCIE:
     * - PageRequest.of(page, size)
     * - page: numer strony (0-based!)
     * - size: ile elementów na stronie
     */
    public void demonstrateBasicPagination() {
        log.info("=== DEMO: Podstawowa paginacja ===");

        // Strona 0, 10 elementów
        Pageable pageable = PageRequest.of(0, 10);
        Page<Pirate> page = pirateRepository.findAll(pageable);

        log.info("Strona: {}/{}", page.getNumber() + 1, page.getTotalPages());
        log.info("Elementów na stronie: {}", page.getNumberOfElements());
        log.info("Wszystkich elementów: {}", page.getTotalElements());
        log.info("Czy jest następna strona: {}", page.hasNext());

        page.getContent().forEach(p -> log.info("  - {}", p.getName()));
    }

    /**
     * Demo 2: Paginacja z sortowaniem.
     * 
     * SORTOWANIE:
     * - Sort.by("field") - rosnąco
     * - Sort.by("field").descending() - malejąco
     * - Sort.by("field1", "field2") - wiele pól
     */
    public void demonstratePaginationWithSorting() {
        log.info("=== DEMO: Paginacja + sortowanie ===");

        // Strona 0, 5 elementów, sortowanie po bounty malejąco
        Pageable pageable = PageRequest.of(0, 5, Sort.by("bounty").descending());
        Page<Pirate> page = pirateRepository.findAll(pageable);

        log.info("Top 5 piratów z największym bounty:");
        page.getContent().forEach(p -> 
            log.info("  - {} ({}): {}", p.getName(), p.getRank(), p.getBounty())
        );
    }

    /**
     * Demo 3: Iteracja przez wszystkie strony.

*/
    public void demonstratePageIteration() {
        log.info("=== DEMO: Iteracja przez strony ===");

        Pageable pageable = PageRequest.of(0, 10);
        Page<Pirate> page = pirateRepository.findAll(pageable);

        int pageNum = 1;
        while (page.hasContent()) {
            log.info("Strona {}: {} piratów", pageNum, page.getNumberOfElements());

            if (!page.hasNext()) {
                break;
            }

            page = pirateRepository.findAll(page.nextPageable());
            pageNum++;
        }

        log.info("Łącznie {} stron", pageNum);
    }

    /**
     * Demo 4: Paginacja z filtrowaniem.
     * 
     * Łączy query method z paginacją.
     */
    public void demonstratePaginationWithFiltering() {
        log.info("=== DEMO: Paginacja + filtrowanie ===");

        // Kapitanowie, sortowani po bounty, strona 0, 5 elementów
        Pageable pageable = PageRequest.of(0, 5, Sort.by("bounty").descending());
        Page<Pirate> captains = pirateRepository.findByRank("Captain", pageable);

        log.info("Kapitanowie (strona 1):");
        captains.getContent().forEach(p -> 
            log.info("  - {}: {}", p.getName(), p.getBounty())
        );

        log.info("Wszystkich kapitanów: {}", captains.getTotalElements());
    }

    /**
     * Demo 5: Złożone sortowanie.
     */
    public void demonstrateComplexSorting() {
        log.info("=== DEMO: Złożone sortowanie ===");

        // Sortowanie: rank rosnąco, potem bounty malejąco
        Sort sort = Sort.by(
            Sort.Order.asc("rank"),
            Sort.Order.desc("bounty")
        );

        Pageable pageable = PageRequest.of(0, 20, sort);
        Page<Pirate> page = pirateRepository.findAll(pageable);

        log.info("Piraci posortowani po randze i bounty:");
        page.getContent().forEach(p -> 
            log.info("  - {} [{}]: {}", p.getName(), p.getRank(), p.getBounty())
        );
    }
}

package pl.przemekzagorski.training.springdata.advanced.service;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;
import org.springframework.data.domain.Sort;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import pl.przemekzagorski.training.springdata.advanced.entity.Pirate;
import pl.przemekzagorski.training.springdata.advanced.projection.PirateNameOnly;
import pl.przemekzagorski.training.springdata.advanced.projection.PirateSummary;
import pl.przemekzagorski.training.springdata.advanced.repository.PirateRepository;

import java.math.BigDecimal;
import java.util.List;

/**
 * 🎯 Serwis demonstracyjny dla Projekcji (Spring Data Projections).
 *
 * KONCEPCJA:
 * - Projekcja = pobieranie tylko wybranych pól z encji
 * - Zamiast SELECT * FROM pirates, wykonuje SELECT name, rank FROM pirates
 * - Interfejs z getterami - Spring Data generuje implementację
 *
 * KORZYŚCI:
 * - Mniej danych z bazy
 * - Szybsze zapytania
 * - Mniejsze zużycie pamięci
 * - Można łączyć z paginacją
 *
 * RÓŻNICA vs Pure JPA:
 * - Pure JPA: SELECT NEW dto.PirateDTO(p.name, p.rank) FROM Pirate p
 * - Spring Data: Interfejs + automatyczna implementacja
 */
@Service
@Transactional(readOnly = true)
public class ProjectionService {

    private static final Logger log = LoggerFactory.getLogger(ProjectionService.class);

    private final PirateRepository pirateRepository;

    public ProjectionService(PirateRepository pirateRepository) {
        this.pirateRepository = pirateRepository;
    }

    /**
     * Demo 1: Podstawowa projekcja.
     * 
     * Porównuje pełną encję vs projekcję.
     */
    public void demonstrateBasicProjection() {
        log.info("=== DEMO: Podstawowa projekcja ===");

        // Pełna encja - wszystkie pola
        log.info("1. Pełna encja (wszystkie pola):");
        List<Pirate> fullPirates = pirateRepository.findByRank("Captain");
        log.info("Pobranych kapitanów: {}", fullPirates.size());
        fullPirates.forEach(p -> log.info("  - {} [{}]", p.getName(), p.getRank()));

        // Projekcja - tylko name i rank
        log.info("2. Projekcja (tylko name i rank):");
        List<PirateNameOnly> projectedPirates = pirateRepository.findProjectedByRank("Captain");
        log.info("Pobranych kapitanów: {}", projectedPirates.size());
        projectedPirates.forEach(p -> log.info("  - {} [{}]", p.getName(), p.getRank()));

        log.info("✅ Projekcja: mniej danych, szybsze zapytanie!");
    }

    /**
     * Demo 2: Projekcja z paginacją.
     * 
     * Najlepsza kombinacja - tylko potrzebne pola + paginacja!
     */
    public void demonstrateProjectionWithPagination() {
        log.info("=== DEMO: Projekcja + paginacja ===");

        Pageable pageable = PageRequest.of(0, 10, Sort.by("bounty").descending());
        Page<PirateSummary> page = pirateRepository.findProjectedByBountyGreaterThan(
            BigDecimal.valueOf(10000), 
            pageable
        );

        log.info("Top 10 piratów z bounty > 10000:");
        log.info("Strona: {}/{}", page.getNumber() + 1, page.getTotalPages());
        log.info("Wszystkich: {}", page.getTotalElements());

        page.getContent().forEach(p -> 
            log.info("  - {}: {}", p.getName(), p.getBounty())
        );
    }

    /**
     * Demo 3: Porównanie wydajności.

* 
     * OBSERWUJ w logach SQL:
     * - Pełna encja: SELECT id, name, rank, bounty, nickname, version, ship_id FROM pirates
     * - Projekcja: SELECT name, rank FROM pirates
     */
    public void comparePerformance() {
        log.info("=== DEMO: Porównanie wydajności ===");

        long start, end;

        // Test 1: Pełna encja
        start = System.currentTimeMillis();
        List<Pirate> fullList = pirateRepository.findByRank("Sailor");
        end = System.currentTimeMillis();
        log.info("Pełna encja: {} rekordów w {} ms", fullList.size(), end - start);

        // Test 2: Projekcja
        start = System.currentTimeMillis();
        List<PirateNameOnly> projectedList = pirateRepository.findProjectedByRank("Sailor");
        end = System.currentTimeMillis();
        log.info("Projekcja: {} rekordów w {} ms", projectedList.size(), end - start);

        log.info("✅ Projekcja jest szybsza (mniej danych do transferu i mapowania)");
    }

    /**
     * Demo 4: Kiedy używać projekcji?
     * 
     * UŻYJ PROJEKCJI gdy:
     * - Potrzebujesz tylko kilku pól
     * - Tworzysz listy/raporty
     * - Optymalizujesz wydajność
     * - Masz duże encje z wieloma polami
     *
     * NIE UŻYWAJ PROJEKCJI gdy:
     * - Potrzebujesz pełnej encji do modyfikacji
     * - Potrzebujesz relacji (@ManyToOne, @OneToMany)
     * - Encja jest mała (niewielka różnica wydajności)
     */
    public void demonstrateUseCases() {
        log.info("=== DEMO: Przypadki użycia projekcji ===");

        // Use case 1: Dropdown list (tylko nazwy)
        log.info("1. Dropdown list - tylko nazwy:");
        List<PirateNameOnly> dropdown = pirateRepository.findProjectedByRank("Captain");
        dropdown.forEach(p -> log.info("  - {}", p.getName()));

        // Use case 2: Ranking (nazwa + bounty)
        log.info("2. Ranking piratów:");
        Pageable top10 = PageRequest.of(0, 10, Sort.by("bounty").descending());
        Page<PirateSummary> ranking = pirateRepository.findProjectedByBountyGreaterThan(
