/**
 * Marker interface dla wszystkich zapytań (Queries).
 * 
 * Query = operacja ODCZYTUJĄCA dane (READ) - NIE ZMIENIA stanu!
 * 
 * 🏴‍☠️ Przykłady:
 * - GetPirateByIdQuery
 * - FindPiratesByRankQuery
 * - CountPiratesQuery
 * 
 * @param <R> Typ wyniku zapytania
 */
public interface Query<R> {
    // Marker interface - nie ma metod
}

package pl.przemekzagorski.training.patterns.cqrs;

import java.util.HashMap;
import java.util.Map;

/**
 * QueryBus - dispatcher dla zapytań.
 * 
 * 🏴‍☠️ Przekazuje zapytania do odpowiednich handlerów.
 * 
 * CQRS: Separacja Commands (zmiany stanu) od Queries (odczyt).
 */
public class QueryBus {

    private final Map<Class<? extends Query<?>>, QueryHandler<? extends Query<?>, ?>> handlers = new HashMap<>();

    /**
     * Rejestruje handler dla danego typu zapytania.
     */
    public <Q extends Query<R>, R> void registerHandler(Class<Q> queryClass, QueryHandler<Q, R> handler) {
        handlers.put(queryClass, handler);
    }

    /**
     * Wykonuje zapytanie - znajduje odpowiedni handler i deleguje do niego.
     */
    @SuppressWarnings("unchecked")
    public <Q extends Query<R>, R> R execute(Q query) {
        QueryHandler<Q, R> handler = (QueryHandler<Q, R>) handlers.get(query.getClass());

        if (handler == null) {
            throw new IllegalArgumentException("No handler registered for query: " + query.getClass().getName());
        }

        return handler.handle(query);
    }
}

package pl.przemekzagorski.training.patterns.cqrs;

/**
 * Handler dla zapytań (Queries).
 * 
 * QueryHandler WYKONUJE zapytania - ODCZYTUJE dane (NIE ZMIENIA stanu!).
 * 
 * @param <Q> Typ zapytania
 * @param <R> Typ wyniku
 */
public interface QueryHandler<Q extends Query<R>, R> {
    /**
     * Wykonuje zapytanie i zwraca wynik.
     * 
     * @param query Zapytanie do wykonania
     * @return Wynik zapytania
     */
    R handle(Q query);
}

package pl.przemekzagorski.training.patterns.cqrs;

/**
 * Komenda: Zaktualizuj nagrodę za głowę pirata.
 * 
 * 🏴‍☠️ Command = ZMIENIA stan (modyfikuje bounty).
 */
public record UpdateBountyCommand(
    Long pirateId,
    int newBounty
) implements Command {
}

package pl.przemekzagorski.training.patterns.cqrs;

/**
 * Handler dla UpdateBountyCommand.
 * 
 * 🏴‍☠️ Aktualizuje nagrodę za głowę pirata.
 */
public class UpdateBountyCommandHandler implements CommandHandler<UpdateBountyCommand> {

    private final PirateDatabase database;

    public UpdateBountyCommandHandler(PirateDatabase database) {
        this.database = database;
    }

    @Override
    public void handle(UpdateBountyCommand command) {
        Pirate pirate = database.findById(command.pirateId())
            .orElseThrow(() -> new IllegalArgumentException("Pirate not found: " + command.pirateId()));

        int oldBounty = pirate.getBounty();
        pirate.setBounty(command.newBounty());

        System.out.println("✅ Updated bounty for " + pirate.getName() + 
            ": " + oldBounty + " → " + command.newBounty());
    }
}

