            case "TREASURE_FOUND" -> System.out.println("   🍳 Kucharz " + name + ": Czas na ucztę!");
            case "RETREAT" -> System.out.println("   🍳 Kucharz " + name + ": Pakuję prowiant!");
            default -> System.out.println("   🍳 Kucharz " + name + ": A co na obiad?");
        }
    }
}

