package pl.przemekzagorski.training.patterns.observer;

/**
 * Demonstracja wzorca Observer.
 *
 * ╔═══════════════════════════════════════════════════════════════════╗
 * ║                      OBSERVER PATTERN                            ║
 * ╠═══════════════════════════════════════════════════════════════════╣
 * ║  PROBLEM:                                                        ║
 * ║    Jeden obiekt (Subject) musi powiadamiać wiele obiektów        ║
 * ║    (Observers) o zmianie stanu.                                  ║
 * ║                                                                  ║
 * ║  ROZWIĄZANIE:                                                    ║
 * ║    Subject trzyma listę Observers i wywołuje ich metodę          ║
 * ║    update() gdy coś się zmienia.                                 ║
 * ║                                                                  ║
 * ║  PRZYKŁADY W JAVIE/FRAMEWORKACH:                                 ║
 * ║    - java.util.Observer (deprecated, ale koncepcja żyje)         ║
 * ║    - Swing: ActionListener, MouseListener                        ║
 * ║    - Spring: ApplicationEventPublisher                           ║
 * ║    - JavaScript: addEventListener                                 ║
 * ╚═══════════════════════════════════════════════════════════════════╝
 */
public class ObserverDemo {

    public static void main(String[] args) {
        System.out.println("🏴‍☠️ OBSERVER PATTERN - Kapitan i załoga");
        System.out.println("=".repeat(55) + "\n");

        // 1️⃣ Tworzymy kapitana (Subject)
        Captain jackSparrow = new Captain("Jack Sparrow");

        // 2️⃣ Tworzymy członków załogi (Observers)
        Gunner gunner = new Gunner("Will Turner");
        Navigator navigator = new Navigator("Gibbs");
        Cook cook = new Cook("Pintel");

        // 3️⃣ Załoga rejestruje się u kapitana
        System.out.println("📋 Rekrutacja załogi:");
        jackSparrow.addObserver(gunner);
        jackSparrow.addObserver(navigator);
        jackSparrow.addObserver(cook);

        // 4️⃣ Kapitan ogłasza wydarzenia
        System.out.println("\n" + "=".repeat(55));
        System.out.println("SCENARIUSZ: Bitwa morska!");
        System.out.println("=".repeat(55));

        jackSparrow.spotEnemy("Okręt Royal Navy na prawej burcie!");

        System.out.println("\n" + "=".repeat(55));
        System.out.println("SCENARIUSZ: Znaleziono skarb!");
        System.out.println("=".repeat(55));

        jackSparrow.findTreasure("Skrzynia ze złotem na wyspie!");

        // 5️⃣ Kucharz opuszcza statek
        System.out.println("\n" + "=".repeat(55));
        System.out.println("Kucharz odchodzi ze statku...");
        jackSparrow.removeObserver(cook);

        System.out.println("\n" + "=".repeat(55));
        System.out.println("SCENARIUSZ: Odwrót!

");

        // 5️⃣ Kucharz opuszcza statek
        System.out.println("\n" + "=".repeat(55));
        System.out.println("Kucharz odchodzi ze statku...");
        jackSparrow.removeObserver(cook);

        System.out.println("\n" + "=".repeat(55));
        System.out.println("SCENARIUSZ: Odwrót!");
        System.out.println("=".repeat(55));

        jackSparrow.orderRetreat();

        System.out.println("\n" + "=".repeat(55));
        System.out.println("✅ KORZYŚCI OBSERVER:");
        System.out.println("   - Kapitan NIE zna szczegółów implementacji załogi");
        System.out.println("   - Możesz dodawać/usuwać obserwatorów dynamicznie");
        System.out.println("   - Łatwe testowanie (mock observers)");
        System.out.println("\n🎯 UŻYJ GDY:");
        System.out.println("   - Zmiana w jednym obiekcie wymaga akcji w innych");
        System.out.println("   - Nie wiesz z góry ILE obiektów będzie reagować");
        System.out.println("   - Chcesz luźne powiązanie (loose coupling)");
    }
}

package pl.przemekzagorski.training.patterns.singleton;

/**
 * Wzorzec SINGLETON - Jeden Kapitan na Statku 🏴‍☠️
 *
 * Problem: Potrzebujemy dokładnie JEDNEJ instancji klasy w całej aplikacji.
 *
 * Przykład piracki: Na każdym statku może być tylko JEDEN kapitan!
 * Nie chcemy przypadkowo stworzyć dwóch kapitanów.
 *
 * Kiedy używać:
 * - Konfiguracja aplikacji
 * - Logger
 * - Connection pool
 * - Cache
 */
public class Captain {

    // Jedyna instancja - przechowywana w zmiennej statycznej
    private static Captain instance;

    private String name;
    private String shipName;

    /**
     * PRYWATNY konstruktor - nikt z zewnątrz nie może wywołać new Captain()!
     */
    private Captain() {
        this.name = "Jack Sparrow";
        this.shipName = "Black Pearl";
        System.out.println("🏴‍☠️ Kapitan " + name + " obejmuje dowodzenie!");
    }

    /**
     * Publiczna metoda do pobierania jedynej instancji.
     *
     * UWAGA: Ta wersja NIE jest thread-safe!
     * W wielowątkowej aplikacji użyj synchronized lub enum.
     */
    public static Captain getInstance() {
        if (instance == null) {
            instance = new Captain();
        }
        return instance;
    }

    public void giveOrder(String order) {
        System.out.println("⚓ Kapitan " + name + " rozkazuje: " + order);
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    public String getShipName() {
        return shipName;
    }
}

package pl.przemekzagorski.training.patterns.singleton;

/**
 * Singleton - wersja THREAD-SAFE przy użyciu enum.
 *
 * Jest to ZALECANA implementacja Singletona w Javie!
 * - Thread-safe "za darmo"
 * - Odporna na serializację
 * - Odporna na refleksję
 */
public enum CaptainEnum {

    INSTANCE;  // Jedyna instancja

    private String name = "Jack Sparrow";
    private String shipName = "Black Pearl";

    public void giveOrder(String order) {
        System.out.println("⚓ Kapitan " + name + " rozkazuje: " + order);
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    public String getShipName() {
        return shipName;
    }
}

package pl.przemekzagorski.training.patterns.singleton;

/**
 * Demonstracja wzorca Singleton.
 */
public class SingletonDemo {

    public static void main(String[] args) {
        System.out.println("🏴‍☠️ Singleton Pattern Demo");
        System.out.println("===========================\n");

        demonstrateBasicSingleton();
        demonstrateEnumSingleton();
    }

    private static void demonstrateBasicSingleton() {
        System.out.println("1️⃣ Podstawowy Singleton\n");

        // Pierwsze pobranie - tworzy instancję
        Captain captain1 = Captain.getInstance();
        captain1.giveOrder("Podnieść kotwicę!");

        // Drugie pobranie - ta sama instancja
        Captain captain2 = Captain.getInstance();
        captain2.giveOrder("Ustawić żagle!");

        // Sprawdzenie czy to ta sama instancja
        System.out.println("\n>>> captain1 == captain2: " + (captain1 == captain2));
        System.out.println(">>> To TA SAMA instancja!\n");

        // Zmiana na jednej referencji wpływa na drugą
        captain1.setName("Hector Barbossa");
        System.out.println(">>> Zmieniono imię przez captain1");
        System.out.println(">>> captain2.getName(): " + captain2.getName());
        System.out.println(">>> Bo to TEN SAM obiekt!\n");
    }

    private static void demonstrateEnumSingleton() {
        System.out.println("2️⃣ Enum Singleton (zalecany!)\n");

        // Dostęp przez INSTANCE
        CaptainEnum captain = CaptainEnum.INSTANCE;
        captain.giveOrder("Kurs na Tortugę!");

        // Zawsze ta sama instancja
        CaptainEnum captain2 = CaptainEnum.INSTANCE;
        System.out.println("\n>>> captain == captain2: " + (captain == captain2));
        System.out.println(">>> Enum gwarantuje jedną instancję!\n");
    }
}

package pl.przemekzagorski.training.patterns.strategy;

/**
 * Interfejs strategii ataku.
 *
 * Wzorzec STRATEGY pozwala wymieniać algorytmy w runtime.
 */
@FunctionalInterface
public interface AttackStrategy {

    /**
     * Wykonuje atak na cel.
     *
     * @param attackerName nazwa atakującego
     * @param targetName nazwa celu
     */
    void attack(String attackerName, String targetName);
}

package pl.przemekzagorski.training.patterns.strategy;

/**
 * Statek piracki używający wzorca Strategy.
 *
 * Strategia ataku może być zmieniana w runtime!
 */
public class BattleShip {

    private String name;
    private AttackStrategy attackStrategy;

    public BattleShip(String name) {
        this.name = name;
        this.attackStrategy = new CannonAttack();  // Domyślna strategia
    }

    /**
     * Zmiana strategii w runtime - serce wzorca Strategy!
     */
    public void setAttackStrategy(AttackStrategy strategy) {
        this.attackStrategy = strategy;
        System.out.println("⚙️ " + name + " zmienia taktykę ataku!");
    }

    /**
     * Wykonuje atak używając aktualnej strategii.
     */
    public void attack(String target) {
        if (attackStrategy == null) {
            System.out.println(name + " nie ma ustawionej strategii ataku!");
            return;
        }
        attackStrategy.attack(name, target);
    }

    public String getName() {
        return name;
    }
}

package pl.przemekzagorski.training.patterns.strategy;

/**
 * Strategia abordażu - wejście na pokład wroga.
 */
public class BoardingAttack implements AttackStrategy {

    @Override
    public void attack(String attackerName, String targetName) {
        System.out.println("⚔️ " + attackerName + " idzie na abordaż " + targetName + "!");
        System.out.println("   Piraci przeskakują na wrogie pokład!");
        System.out.println("   Dystans: bliski, Ryzyko: wysokie, Łupy: maksymalne!");
    }
}

package pl.przemekzagorski.training.patterns.strategy;

/**
 * Strategia ataku armatami - z daleka.
 */
public class CannonAttack implements AttackStrategy {

    @Override
    public void attack(String attackerName, String targetName) {
        System.out.println("💣 " + attackerName + " atakuje " + targetName + " salwą armatnią!");
        System.out.println("   BOOM! BOOM! BOOM!");
        System.out.println("   Dystans: daleki, Obrażenia: wysokie");
    }
}

package pl.przemekzagorski.training.patterns.strategy;

/**
 * Strategia taranowania - desperacki atak.
 */
public class RammingAttack implements AttackStrategy {

    @Override
    public void attack(String attackerName, String targetName) {
        System.out.println("🚢💥 " + attackerName + " taranuje " + targetName + "!");
        System.out.println("   TRZASK! Drewno pęka!");
        System.out.println("   Dystans: zero, Ryzyko: MAKSYMALNE, Desperacja: TAK!");
    }
}

package pl.przemekzagorski.training.patterns.strategy;

/**
 * Demonstracja wzorca Strategy.
 */
public class StrategyDemo {

    public static void main(String[] args) {
        System.out.println("🏴‍☠️ Strategy Pattern Demo");
        System.out.println("===========================\n");

        demonstrateWithoutStrategy();
        demonstrateWithStrategy();
        demonstrateWithLambda();
    }

    /**
     * BEZ Strategy - if/else koszmar.
     */
    private static void demonstrateWithoutStrategy() {
        System.out.println("1️⃣ BEZ Strategy (zły kod z if/else)\n");

        System.out.println("""
            void attack(String type, String target) {
                if (type.equals("cannon")) {
                    // 20 linii kodu ataku armatami
                } else if (type.equals("boarding")) {
                    // 20 linii kodu abordażu
                } else if (type.equals("ramming")) {
                    // 20 linii kodu taranowania
                } else if (type.equals("torpedo")) {  // Nowy typ!
                    // 20 linii kodu
                }
                // Metoda rośnie i rośnie...
            }
            
            ❌ Naruszenie Open/Closed Principle
            ❌ Trudne do testowania
            ❌ Jedna wielka metoda
            """);
    }

    /**
     * Z Strategy - elegancki polimorfizm.
     */
    private static void demonstrateWithStrategy() {
        System.out.println("2️⃣ Z Strategy (dobry kod)\n");

        BattleShip blackPearl = new BattleShip("Black Pearl");
        String enemy = "HMS Interceptor";

        // Domyślna strategia: armaty
        System.out.println(">>> Atak domyślną strategią (armaty):");
        blackPearl.attack(enemy);

        // Zmiana strategii na abordaż
        System.out.println("\n>>> Zmiana strategii na abordaż:");
        blackPearl.setAttackStrategy(new BoardingAttack());
        blackPearl.attack(enemy);

        // Desperacki manewr - taranowanie!
        System.out.println("\n>>> Sytuacja krytyczna - taranowanie!");
        blackPearl.setAttackStrategy(new RammingAttack());
        blackPearl.attack(enemy);

        System.out.println("""
            
            ✅ Każda strategia w osobnej klasie
            ✅ Łatwo dodać nową strategię (nowa klasa)
            ✅ Łatwo testować każdą strategię osobno
            ✅ Można zmieniać strategię w runtime
            """);
    }

    /**
     * Strategy z lambdami - dla prostych przypadków.
     */
    private static void demonstrateWithLambda() {
        System.out.println("3️⃣ Strategy z lambdami (Java 8+)\n");

        BattleShip flyingDutchman = new BattleShip("Flying Dutchman");

        // Strategy jako lambda!
        flyingDutchman.setAttackStrategy((attacker, target) -> {
            System.out.println("🦑 " + attacker + " uwalnia Krakena na " + target + "!");
            System.out.println("   Macki oplatają wrogi statek!");
        });

        flyingDutchman.attack("HMS Endeavour");

        System.out.println("""
            
            ✅ Dla prostych strategii - lambda wystarczy
            ✅ Nie trzeba tworzyć osobnej klasy
            ✅ @FunctionalInterface umożliwia lambdy
            """);
    }
}

